INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 401, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", "2030/12/17 14:59:59", 10046, 102301, 24001, 0.0, "2020/07/31 12:00:00", 0.0, 0.0, 2, "アヤネ", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 402, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", "2030/12/17 14:59:59", 10046, 102301, 24002, 2.21, "2020/07/31 12:00:00", 0.0, 0.0, 1, "アヤネ", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 403, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", "2030/12/17 14:59:59", 10046, 102301, 24003, 0.0, "2020/07/31 12:00:00", 0.0, 0.0, 2, "アヤネ", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 701, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", "2030/12/17 14:59:59", 10046, 192201, 24004, 1.99, "2020/07/31 12:00:00", 0.0, 0.0, 2, "アサヒ", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 702, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", "2030/12/17 14:59:59", 10046, 192201, 24005, 2.21, "2020/07/31 12:00:00", 0.0, 0.0, 1, "アサヒ", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 703, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", "2030/12/17 14:59:59", 10046, 192201, 24006, 3.33, "2020/07/31 12:00:00", 0.0, 0.0, 2, "アサヒ", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 801, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", "2030/12/17 14:59:59", 10046, 192301, 24007, 0.0, "2020/07/31 12:00:00", 0.0, 0.0, 2, "部員３", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 802, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", "2030/12/17 14:59:59", 10046, 192301, 24008, 2.68, "2020/07/31 12:00:00", 0.0, 0.0, 1, "部員３", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 803, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", "2030/12/17 14:59:59", 10046, 192301, 24009, 0.0, "2020/07/31 12:00:00", 0.0, 0.0, 2, "部員３", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 501, "やった！", "2030/12/17 14:59:59", 10046, 192501, 24010, 0.0, "2020/07/31 12:00:00", 0.0, 0.0, 1, "", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 502, "勝ったよ！", "2030/12/17 14:59:59", 10046, 192501, 24011, 0.0, "2020/07/31 12:00:00", 0.0, 0.0, 1, "", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 503, "いい調子！", "2030/12/17 14:59:59", 10046, 192501, 24012, 0.0, "2020/07/31 12:00:00", 0.0, 0.0, 1, "", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 111, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", "2030/12/17 14:59:59", 10046, 113501, 24013, 5.33, "2020/07/31 12:00:00", 0.0, 0.0, 6, "ミサト", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 112, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", "2030/12/17 14:59:59", 10046, 113501, 24014, 6.85, "2020/07/31 12:00:00", 0.0, 0.0, 1, "ミサト", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 113, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", "2030/12/17 14:59:59", 10046, 113501, 24015, 3.0, "2020/07/31 12:00:00", 0.0, 0.0, 1, "ミサト", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 611, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", "2030/12/17 14:59:59", 10046, 192401, 24016, 6.11, "2020/07/31 12:00:00", 0.0, 0.0, 1, "ダイチ", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 612, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", "2030/12/17 14:59:59", 10046, 192401, 24017, 6.75, "2020/07/31 12:00:00", 0.0, 0.0, 1, "ダイチ", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 613, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", "2030/12/17 14:59:59", 10046, 192401, 24018, 0.0, "2020/07/31 12:00:00", 0.0, 0.0, 2, "ダイチ", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 211, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", "2030/12/17 14:59:59", 10046, 113401, 24019, 4.52, "2020/07/31 12:00:00", 0.0, 0.0, 2, "ハツネ", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 212, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", "2030/12/17 14:59:59", 10046, 113401, 24020, 3.89, "2020/07/31 12:00:00", 0.0, 0.0, 2, "ハツネ", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 213, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", "2030/12/17 14:59:59", 10046, 113401, 24021, 13.49, "2020/07/31 12:00:00", 0.0, 0.0, 1, "ハツネ", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 311, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", "2030/12/17 14:59:59", 10046, 106501, 24022, 3.17, "2020/07/31 12:00:00", 0.0, 0.0, 1, "カヤ", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 312, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", "2030/12/17 14:59:59", 10046, 106501, 24023, 4.42, "2020/07/31 12:00:00", 0.0, 0.0, 1, "カヤ", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 313, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", "2030/12/17 14:59:59", 10046, 106501, 24024, 2.89, "2020/07/31 12:00:00", 0.0, 0.0, 6, "カヤ", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 421, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", "2030/12/17 14:59:59", 10046, 102301, 24025, 3.71, "2020/07/31 12:00:00", 0.0, 0.0, 4, "アヤネ", 3);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 721, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", "2030/12/17 14:59:59", 10046, 192201, 24026, 5.1, "2020/07/31 12:00:00", 0.0, 0.0, 2, "アサヒ", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 821, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", "2030/12/17 14:59:59", 10046, 192301, 24027, 4.34, "2020/07/31 12:00:00", 0.0, 0.0, 1, "部員３", 3);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 521, "いい勝負だったよ\nまたやろうね", "2030/12/17 14:59:59", 10046, 192501, 24028, 0.0, "2020/07/31 12:00:00", 0.0, 0.0, 1, "", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 101, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", "2030/12/17 14:59:59", 10046, 113501, 24029, 5.62, "2020/07/31 12:00:00", 0.0, -360.0, 1, "ミサト", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 102, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", "2030/12/17 14:59:59", 10046, 113501, 24030, 9.58, "2020/07/31 12:00:00", 0.0, -360.0, 1, "ミサト", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 103, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", "2030/12/17 14:59:59", 10046, 113501, 24031, 0.0, "2020/07/31 12:00:00", 0.0, -360.0, 2, "ミサト", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 104, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", "2030/12/17 14:59:59", 10046, 113501, 24032, 9.13, "2020/07/31 12:00:00", 0.0, -360.0, 2, "ミサト", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 105, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", "2030/12/17 14:59:59", 10046, 113501, 24033, 8.27, "2020/07/31 12:00:00", 0.0, -360.0, 1, "ミサト", 2);
